 pub fn loom_asset_blob_path(
     handshake_root: &Path,
     workspace_id: &str,
     asset_kind: &str,
     content_hash: &str,
 ) -> PathBuf {
     let tier_dir = match asset_kind {
         "original" => LOOM_ASSET_ORIGINAL_DIR,
         "thumbnail" => LOOM_ASSET_PREVIEW_DIR,
         "proxy" => LOOM_ASSET_PROXY_DIR,
         _ => "blobs",
     };

     handshake_root
         .join("data")
         .join("workspaces")
         .join(workspace_id)
         .join(LOOM_ASSET_DIR)
         .join(tier_dir)
         .join(content_hash)
 }

